# modules/team-subscription/variables.tf
variable "teams" {
  description = "Map of teams to provision subscriptions for"
  type = map(object({
    display_name          = string
    billing_scope_id      = string
    management_group_id   = string
    owner_group_object_id = string
    monthly_budget_usd    = number
    workload              = optional(string, "Production")
    tags                  = optional(map(string), {})
  }))
  default = {}
}

# modules/team-subscription/main.tf
resource "azurerm_subscription" "team" {
  for_each          = var.teams
  subscription_name = each.key
  billing_scope_id  = each.value.billing_scope_id
  workload          = each.value.workload
  tags = merge(each.value.tags, {
    managed-by = "platform"
    team       = each.key
  })
}

resource "azurerm_management_group_subscription_association" "team" {
  for_each            = var.teams
  management_group_id = each.value.management_group_id
  subscription_id     = "/subscriptions/${azurerm_subscription.team[each.key].subscription_id}"
  depends_on          = [azurerm_subscription.team]
}

resource "azurerm_role_assignment" "team_owner" {
  for_each             = var.teams
  scope                = "/subscriptions/${azurerm_subscription.team[each.key].subscription_id}"
  role_definition_name = "Owner"
  principal_id         = each.value.owner_group_object_id
  depends_on           = [azurerm_subscription.team]
}

# Platform Reader at subscription scope — visibility without control
variable "platform_reader_group_id" { type = string }

resource "azurerm_role_assignment" "platform_reader" {
  for_each             = var.teams
  scope                = "/subscriptions/${azurerm_subscription.team[each.key].subscription_id}"
  role_definition_name = "Reader"
  principal_id         = var.platform_reader_group_id
  depends_on           = [azurerm_subscription.team]
}

resource "azurerm_consumption_budget_subscription" "team" {
  for_each        = var.teams
  name            = "${each.key}-monthly"
  subscription_id = "/subscriptions/${azurerm_subscription.team[each.key].subscription_id}"
  amount          = each.value.monthly_budget_usd
  time_grain      = "Monthly"
  time_period {
    start_date = "2026-07-01T00:00:00Z"
    end_date   = "2027-07-01T00:00:00Z"
  }
  notification {
    enabled        = true
    operator       = "GreaterThan"
    threshold      = 80
    contact_roles  = ["Owner"]
  }
  depends_on = [azurerm_subscription.team]
}

# outputs.tf
output "subscription_ids" {
  description = "Map from team name to subscription ID"
  value = { for k, v in azurerm_subscription.team : k => v.subscription_id }
}

